    if (value === null) {
      form.delete(key);
    } else if (value !== undefined) {
      form.set(key, value);
    }
  }

  return form.toString();
}

export async function createOidcToken(
  overrides?: Partial<Record<string, unknown>>,
  options?: CreateOidcTokenOptions,
): Promise<string> {
